"""
MKT Christ Commentary — Isaiah 3 (26 verses)
Run: python3 scripts/zc-christ-isaiah-3.py
Key decisions:
- vv1-7: YHWH removes every human prop/support (bread, warrior, judge, prophet,
  elder) — shadow: the stripping of every human resource to reveal dependence
  on Christ alone (John 15:5); the vacuum of leadership fulfilled by the one
  Leader (Matt 23:10)
- v9: Sodom-comparison for Jerusalem's brazen sin — Luke 10:12 / Jude 7
  Sodom as the paradigm of judgment awaiting cities that reject the gospel
- v10-11: The righteous-vs-wicked destiny distinction — shadow of the last
  judgment (Matt 25:31-46); the fruit-of-works principle (Rev 22:12)
- v13-15: YHWH rises to judge the oppressor-leaders of his people —
  theme: Acts 17:31 (the day of judgment appointed through Christ); the cry
  of the poor reaching YHWH's court anticipates James 5:4-6
- v24: Exchange of beauty for burning/branding — type/inversion: 2 Cor 5:21
  (Christ took the shame so the redeemed receive beauty); Isa 61:3 (beauty
  for ashes) is the positive answer to Isaiah 3:24's negative exchange
- v26: Zion's gates mourn, she sits desolate — Luke 19:41-44 (Jesus weeps
  over Jerusalem); Matt 23:38 ("your house is left to you desolate")
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent


def load_comm(layer, book):
    p = ROOT / "data" / "commentary" / layer / f"{book}.json"
    return json.loads(p.read_text()) if p.exists() else {}


def save_comm(layer, book, data):
    p = ROOT / "data" / "commentary" / layer / f"{book}.json"
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=2))


def merge_comm(existing, new_data):
    # INTENT: Write only absent keys so re-running is safe after manual edits.
    # CHANGE? If isaiah.json schema changes, update merge_comm and ISAIAH dict below.
    # VERIFY: python3 -c "import json; d=json.load(open('data/commentary/mkt-christ/
    #   isaiah.json')); print('Isa 3 v13:',d.get('3',{}).get('13','MISSING')[:60])"
    for ch, verses in new_data.items():
        existing.setdefault(ch, {})
        for v, text in verses.items():
            existing[ch].setdefault(v, text)


ISAIAH = {
    "3": {
        "1": "<p>\"For behold, the Lord YHWH of Hosts is taking away from Jerusalem and Judah every support of bread and every support of water\" — the divine removal of the basics of life as a form of judgment. The cascade that follows strips Jerusalem of every form of human leadership and resource. This reveals the shadow pattern that Christ will later fulfill positively: John 6:35 (\"I am the bread of life; whoever comes to me will never go hungry\") answers the removal of bread-support here; Christ himself is the sustaining support that human leadership and food supply only ever pointed toward. Where YHWH removes every prop to expose the community's fragility, Christ offers himself as the one prop that cannot be removed.</p>",
        "2": "<p>The support-list continues: the mighty man (<em>gibbôr</em>), the warrior, the judge, the prophet, the diviner, the elder — the complete range of leadership functions. Each represents a form of human governance and wisdom that Jerusalem has relied on. The total removal of these figures is the judgment — and simultaneously a typological pointer: Matthew 23:10 (\"for you have one Teacher, the Christ\") and John 5:22 (\"the Father judges no one, but has entrusted all judgment to the Son\") show Christ as the one who fulfills every office listed here — prophet, priest, king, judge — that the removed leaders had held in shadow. The vacuum created by divine removal is the space that Christ alone fills.</p>",
        "3": "<p>\"The captain of fifty and the man of high rank, the counselor and the expert craftsman and the skillful enchanter\" — the leadership stripping extends to military and administrative officers, craftsmen, and even those with occult knowledge. The inclusion of the \"skillful enchanter\" (<em>nĕbôn laḥaš</em>) in the list of those being removed suggests that Jerusalem had been relying on divination alongside legitimate leadership. 1 Corinthians 1:20: \"Where is the wise person? Where is the teacher of the law? Where is the philosopher of this age? Has not God made foolish the wisdom of the world?\" — the stripping of Jerusalem's wise men anticipates the cross's dismantling of all human pretension to wisdom and power.</p>",
        "4": "<p>\"And I will make boys their princes, and infants will rule over them\" — the vacuum of mature leadership filled by immature rulers is both judgment and comic inversion. When YHWH removes the able, the incapable fill the space. The irony deepens in Christological perspective: Matthew 11:25 (\"you have hidden these things from the wise and learned, and revealed them to little children\") shows that divine revelation inverts the expected order — what the mature leaders of Jerusalem could not perceive, the childlike receive. The \"boys ruling\" is the judgment form of the same inversion that becomes grace in the kingdom: the humble are exalted (Luke 1:52).</p>",
        "5": "<p>\"The people will oppress one another, every one his neighbor; the young will be insolent to the elder, and the base to the honorable\" — the social breakdown that follows leadership vacuum: every hierarchical and honor structure collapses. This is the covenant curse condition — the Deuteronomy 28 trajectory of social disintegration when the community abandons YHWH. The social shalom that Christ restores through the new covenant (\"love one another as I have loved you,\" John 13:34) is the positive answer to the social disintegration of Isaiah 3:5. Where judgment removes the ordering of love, Christ reinstalls it from within.</p>",
        "6": "<p>\"When a man grabs his brother in his father's house: 'You have a cloak! Be our leader; this ruin is under your authority!'\" — the desperation of a leaderless community grasping at anyone with minimal resources. The cloak (<em>śimlāh</em>) becomes the sole qualification for leadership. The irony: the soldiers gambling for Christ's cloak at the crucifixion (John 19:23-24) is the inverse — the one who is truly the Leader is stripped of his cloak and authority appears to be taken from him; in reality, it is at that moment that his kingship is most fully exercised (John 19:19-22: \"Pilate had a notice prepared and fastened to the cross. It read: 'Jesus of Nazareth, the King of the Jews'\"</p>",
        "7": "<p>\"In that day he will swear: 'I will not be your healer; in my house there is neither bread nor cloak; you shall not make me leader of the people'\" — the refusal of leadership when the resources for it are gone. The reluctant leader who refuses the burden: contrast with Christ who actively takes on the burden of leadership through service, not coercion — \"The Son of Man did not come to be served, but to serve, and to give his life as a ransom for many\" (Matthew 20:28). Where every capable person in Jerusalem refuses the call, the one who is capable by nature takes on what no one else can bear.</p>",
        "8": "<p>\"For Jerusalem has stumbled, and Judah has fallen, because their speech and their deeds are against the LORD, defying his glorious presence\" — the verdict: the city falls because its words and works stand against YHWH himself. The word for \"defying\" (<em>mārôt</em>) is the same root as the Wilderness rebellion narratives (Num 20:24). Jerusalem repeats the wilderness pattern — the community that was delivered from Egypt now defies the God who delivered them. Luke 13:34: \"Jerusalem, Jerusalem, you who kill the prophets and stone those sent to you — how often I have longed to gather your children together, as a hen gathers her chicks under her wings, and you were not willing.\" Christ's lament over Jerusalem is the end-point of the city's defiant trajectory that Isaiah 3:8 diagnoses.</p>",
        "9": "<p>\"The look on their faces witnesses against them; they parade their sin like Sodom, they do not conceal it\" — the brazen visibility of the sin; shame has been dissolved and transgression is publicly displayed. The Sodom comparison is the most severe the OT deploys — Sodom is the paradigm of judgment in Genesis 19, and its mention here classifies Jerusalem's condition as Sodom-level. Luke 10:12 (\"I tell you, it will be more bearable on that day for Sodom than for that town\") — Jesus applies this same Sodom-comparison to towns that reject the gospel, escalating Isaiah's use of Sodom: the judgment for rejecting the embodied Word is even greater than for the brazen visibility of Sodom's sin. \"Woe to them! For they have brought evil on themselves.\"</p>",
        "10": "<p>\"Tell the righteous that it will go well with them, for they will eat the fruit of their deeds\" — the promise embedded in the judgment: even in the catastrophe of Jerusalem's fall, the righteous person will receive according to their deeds. The fruit-of-deeds principle points toward the final judgment. Revelation 22:12 (\"My reward is with me, and I will give to each person according to what they have done\") — Christ as the judge who rewards the righteous is the fulfillment of this promise. The judgment of Jerusalem is not the final judgment, but it operates by the same principle that will govern the last day: the righteous receive fruit of righteousness, not because they earned their standing but because their deeds reflect the new nature given by grace.</p>",
        "11": "<p>\"Woe to the wicked! Disaster is upon them! They will be paid back for what their hands have done\" — the mirror principle: the fruit of wickedness returns to the wicked. This is the covenant curse structure: Deuteronomy 28 makes clear that blessing and curse attach to the direction of covenant fidelity. But the gospel introduces a stunning intervention into this principle: 2 Corinthians 5:21 — \"God made him who had no sin to be sin for us, so that in him we might become the righteousness of God.\" Christ takes the \"paid back for what their hands have done\" that the wicked deserved — he receives the woe of Isaiah 3:11 on behalf of his people. The retribution principle is not abolished but absorbed into atonement.</p>",
        "12": "<p>\"My people's oppressors are children, and women rule over them. O my people, your guides mislead you and they have swallowed up the direction of your paths\" — the leadership inversion again: those who should lead are unable; those who guide lead astray. The \"swallowing up\" of the paths is the destruction of the covenant way of life through bad leadership. John 10:11-13: the false shepherd who abandons the sheep versus the good shepherd who lays down his life. The guides who mislead in Isaiah 3:12 are the shepherds who flee when the wolf comes; Christ is the shepherd who stays. \"The thief comes only to steal and kill and destroy; I have come that they may have life, and have it to the full\" (John 10:10).</p>",
        "13": "<p>\"The LORD takes his stand to accuse; he stands to judge his people\" — the divine entry into the courtroom as accuser and judge. The legal-assembly image: YHWH stands to initiate proceedings. Acts 17:31: \"For he has set a day when he will judge the world with justice by the man he has appointed.\" The Father who stands to judge in Isaiah 3:13 has appointed the Son as judge: John 5:22-23 (\"the Father judges no one, but has entrusted all judgment to the Son\") and John 5:27 (\"he has given him authority to judge because he is the Son of Man\"). The standing-to-judge of Isaiah 3:13 is fulfilled in the great-white-throne judgment of Revelation 20:11-13 through Christ.</p>",
        "14": "<p>\"The LORD enters into judgment with the elders and princes of his people: 'It is you who have devoured the vineyard; the spoil of the poor is in your houses'\" — the specific charge against the leaders: they have plundered the poor. The vineyard (<em>kerem</em>) is Israel itself (cf. Isa 5:1-7); the leaders have consumed what was entrusted to their care. James 5:4: \"Look! The wages you failed to pay the workers who mowed your fields are crying out against you.\" 5:6: \"You have condemned and murdered the innocent one, who was not opposing you.\" James's indictment of the rich in the new covenant era applies the same forensic logic as Isaiah 3:14: the cry of the oppressed poor reaches the LORD of Sabaoth (James 5:4 = YHWH of Hosts).</p>",
        "15": "<p>\"What do you mean by crushing my people and grinding the face of the poor?\" declares the Lord YHWH of Hosts — the divine cross-examination that admits no defense. The grinding of the poor's face is the violence of grinding grain: the poor are reduced to powder under economic oppression. Luke 4:18 (\"to proclaim release to the oppressed\") — the Servant's mission in Isaiah 61:1 (the text Jesus reads in Nazareth) is the direct answer to the oppression of Isaiah 3:15: where YHWH's question exposes the injustice, the Servant's mission announces the release. The cry of the poor that reaches YHWH in Isaiah 3 reaches its answer in the ministry of the one anointed to set the oppressed free.</p>",
        "16": "<p>\"The LORD says: because the daughters of Zion are haughty and walk with outstretched necks, glancing wantonly with their eyes\" — the women of Jerusalem representing the city's arrogance through their conspicuous display. The extended description of their adornments and the judgment that strips each one away mirrors the structure of atonement in reverse: where the fall involves the acquisition of ornament as self-assertion, redemption involves the voluntary stripping of self-assertion. Philippians 2:5-8: Christ \"did not consider equality with God something to be used to his own advantage; rather, he made himself nothing... he humbled himself\" — the opposite direction from the daughters of Zion's self-display.</p>",
        "17": "<p>\"The Lord will strike with scabs the heads of the daughters of Zion, and the LORD will lay bare their secret parts\" — the judgment that reverses the beautification: the adorned head struck with scabs, the covered body exposed. The stripping of dignity as divine judgment echoes the exposure language of Ezekiel 16 (Jerusalem as an unfaithful wife stripped and publicly shamed). The Christological inversion: at the crucifixion, Christ is stripped of his garments (John 19:23-24) — the dignity that belonged to the sinless one is taken from him so that the dignity that was stripped from the guilty can be restored. The shame of the cross answers the shame decreed in Isaiah 3:17.</p>",
        "18": "<p>\"In that day the Lord will take away the finery of the anklets, the headbands, and the crescents\" — the beginning of the long list of ornaments that will be removed. \"In that day\" marks the eschatological-judgment form of the stripping; it is not merely the Babylonian exile but the final accounting of all self-assertion before YHWH. The ornamental list (vv18-23) is the physical inventory of everything Zion trusted in for beauty and status rather than trusting YHWH. Revelation 18:11-17 catalogs the luxury goods of Babylon that will be lost when the great city falls — the same structural critique: all accumulated ornament is vapor before divine judgment.</p>",
        "19": "<p>\"The pendants, the bracelets, and the scarves\" — the list of adornments continues. Each item cataloged is a form of self-presentation, of constructed identity through external markers. The exhaustive detail of the inventory is itself part of the judgment: every specific item of pride is named and targeted for removal. The contrast is with Revelation 19:8 (\"fine linen, bright and clean, was given her to wear\") — the bride of the Lamb receives her righteousness as a gift, not as self-constructed ornament. What Zion accumulated through self-assertion, the church receives through grace: the wedding garment of righteousness is given, not purchased or manufactured.</p>",
        "20": "<p>\"The headdresses, the ankle bracelets, and the sashes, the perfume boxes, and the amulets\" — the list includes amulets (<em>leḥāšîm</em>), which overlaps with the divination-language of the chapter: the daughters of Zion wore protective charms, trusting in occult protection alongside their other resources. This compounds the indictment: not merely pride in beauty but reliance on magical protection rather than YHWH. The theme of misplaced trust in protection is answered in Christ: Colossians 2:15 (\"having disarmed the powers and authorities, he made a public spectacle of them, triumphing over them by the cross\") — the one who truly protects is Christ, who has defeated the spiritual powers that the amulets ineffectually invoked.</p>",
        "21": "<p>\"The signet rings and nose rings\" — the signet ring (<em>ṭabbaʿōt</em>) is a mark of authority and identity: important documents were sealed with the signet. Its removal signals the stripping of official status and identity. The loss of the signet is the loss of recognized standing. Haggai 2:23 promises the opposite: YHWH will make Zerubbabel like a signet ring, reinstating the covenant authority that was stripped. Ephesians 1:13-14: the Spirit is the divine seal on the believer — the permanent, unremovable signet of belonging to God that the daughters of Zion's physical rings only faintly shadowed. Christ restores what the judgment removes: the seal of the Spirit replaces the stripped signet ring.</p>",
        "22": "<p>\"The festal robes, the mantles, the cloaks, and the handbags\" — the outer garments of status. The mantle (<em>maʿăṭeh</em>) is the same word used in Isaiah 61:3 for the \"mantle of praise\" that replaces the spirit of despair. Here in chapter 3 the mantle is stripped; in chapter 61 a new mantle is given. The trajectory of Isaiah itself traces the movement from stripping to re-robing: what judgment removes, redemption restores in a higher form. Galatians 3:27: \"for all of you who were baptized into Christ have clothed yourselves with Christ\" — the final garment is not a cloak or mantle but Christ himself, the ultimate clothing of the redeemed.</p>",
        "23": "<p>\"The mirrors, the linen garments, the turbans, and the veils\" — the list ends with items that touch the face and identity most directly: mirrors for self-examination, veils for concealment or modesty. 2 Corinthians 3:18: \"we all, who with unveiled faces contemplate the Lord's glory, are being transformed into his image with ever-increasing glory\" — the veil removed is not the judgment-stripping of Isaiah 3 but the removal of the Mosaic veil (2 Cor 3:13-16) that concealed the glory. The unveiled face of the new covenant is the answer to the veils removed in judgment: both are unveilings, but one is the stripping of pride and the other is the revelation of glory.</p>",
        "24": "<p>\"Instead of perfume there will be rottenness; instead of a belt, a rope; instead of well-set hair, baldness; instead of a rich robe, a skirt of sackcloth; instead of beauty, branding\" — the five-fold exchange of beauty for its opposite, the anti-type of Isaiah 61:3's triple exchange (beauty for ashes, gladness for mourning, praise for despair). Here the judgment reverses all ornament into its negative: the aromatic perfume becomes decay, the elegant belt becomes rough rope, the styled hair becomes the shaved head of captivity, the fine robe becomes the coarsest mourning cloth, and beauty becomes the mark of branding (as a slave or criminal). 2 Corinthians 5:21: Christ underwent the ultimate exchange in reverse — \"He who had no sin became sin for us, so that in him we might become the righteousness of God.\" The branding of Isaiah 3:24 is what Christ absorbs in our place; the beauty of Isaiah 61:3 is what his people receive in exchange.</p>",
        "25": "<p>\"Your men shall fall by the sword and your mighty men in battle\" — the military dimension of the judgment: the warriors who were removed in vv1-3 are now not merely absent but fallen. The city that relied on its fighting men for security loses them to the very war they were supposed to prevent. Zechariah 12:10: \"I will pour out on the house of David and the inhabitants of Jerusalem a spirit of grace and supplication. They will look on me, the one they have pierced, and they will mourn for him as one mourns for an only child.\" The mourning of Jerusalem over its fallen men in Isaiah 3:25 is answered by the eschatological mourning over the pierced one — the grief of the city finds its final object in the crucified Christ.</p>",
        "26": "<p>\"And her gates shall mourn and lament, and she shall empty herself and sit on the ground\" — the personification of the city as a widow sitting desolate on the ground: the posture of Lamentations 1:1 (\"How deserted lies the city, once so full of people! How like a widow is she\"). Luke 19:41-44: \"As he approached Jerusalem and saw the city, he wept over it and said, 'If you, even you, had only known on this day what would bring you peace — but now it is hidden from your eyes.'\" Matthew 23:38: \"Look, your house is left to you desolate.\" Christ's weeping over Jerusalem and his pronouncement of desolation is the fulfillment of Isaiah 3:26 — the city that has rejected every prophet is left desolate, sitting on the ground. Yet even from this desolation, Romans 11:26 promises: \"all Israel will be saved\" — the empty city will not remain empty forever.</p>"
    }
}


def main():
    existing = load_comm("mkt-christ", "isaiah")
    before = sum(len(v) for v in existing.values())
    merge_comm(existing, ISAIAH)
    after = sum(len(v) for v in existing.values())
    save_comm("mkt-christ", "isaiah", existing)
    print(f"{len(existing)} chapters, {after} verse entries total (+{after - before} new)")
    for v, kw in [("9", "Sodom"), ("13", "judge"), ("24", "exchange"), ("26", "desolate")]:
        entry = existing.get("3", {}).get(v, "MISSING")
        print(f"  Isa 3:{v} — {'OK' if kw.lower() in entry.lower() else 'CHECK'}")
    ch = existing.get("3", {})
    missing = [str(i) for i in range(1, 27) if str(i) not in ch]
    print(f"  Missing verses: {missing if missing else 'none'}")


if __name__ == "__main__":
    main()
